 fn init_schema_sqlite_canonical(path: &str) -> CliResult<()> {
-    let conn = sqlmodel_sqlite::SqliteConnection::open_file(path)
-        .map_err(|e| CliError::Other(format!("cannot open DB at {path} for schema init: {e}")))?;
