-    })?;
-    Ok(())
+        conn.execute_raw("PRAGMA busy_timeout = 60000;")
+            .map_err(|e| {
+                sqlite_retryable_error(
+                    format!("failed to apply busy_timeout for {path} via canonical sqlite: {e}"),
+                    &e.to_string(),
+                )
+            })?;
+        conn.execute_raw(mcp_agent_mail_db::schema::PRAGMA_DB_INIT_BASE_SQL)
